function discoverBridges() {
  let files;
  try {
    files = fs2.readdirSync(DISCOVERY_DIR).filter((f) => f.startsWith("vscode-") && f.endsWith(".json")).map((f) => path3.join(DISCOVERY_DIR, f));
  } catch {
    return [];
  }
  files.sort((a, b) => fs2.statSync(b).mtimeMs - fs2.statSync(a).mtimeMs);
  const bridges = [];
  for (const f of files) {
    try {
      const d = JSON.parse(fs2.readFileSync(f, "utf8"));
      bridges.push({ url: d.url, token: d.token, pid: Number(d.pid ?? 0) });
    } catch {
      continue;
    }
  }
  return bridges;
}
async function findEditor() {
  for (const b of discoverBridges()) {
    const ed = new Editor(b);
    try {
      await ed.health();
      return ed;
    } catch {
      continue;
    }
  }
  return null;
}

